const execData = $json.data?.resultData?.runData;
const triggerData = $('When Executed by Another Workflow').first().json;

const groqRuns = execData?.['Groq Chat Model'] || [];
const tokenTotals = groqRuns.reduce((acc, run) => {
  const usage = run?.data?.ai_languageModel?.[0]?.[0]?.json?.tokenUsage;
  if (!usage) return acc;
  return {
    input: acc.input + (usage.promptTokens ?? 0),
    output: acc.output + (usage.completionTokens ?? 0),
    total: acc.total + (usage.totalTokens ?? 0),
  };
}, { input: null, output: null, total: null });

const hasTokens = groqRuns.some(
  run => run?.data?.ai_languageModel?.[0]?.[0]?.json?.tokenUsage
);

const skipNodes = new Set([
  'Groq Chat Model',
  'Vision Agent',
  'MyGuy AI Agent',
  'Postgres Chat Memory',
  'Incoming Payload',
  'Prepare for logger',
  "Call 'Token Logger'",
  'Respond To Input',
]);

const toolsCalled = Object.entries(execData || {})
  .filter(([nodeName, runs]) =>
    !skipNodes.has(nodeName) &&
    runs.some(run => run?.data?.ai_tool || run?.inputOverride?.ai_tool)
  )
  .flatMap(([nodeName, runs]) =>
    runs.map(run => ({
      tool: nodeName,
      status: run.executionStatus,
      executionTime: run.executionTime,
      ...(run.inputOverride?.ai_tool?.[0]?.[0]?.json?.message && {
        input: run.inputOverride.ai_tool[0][0].json.message
      }),
      ...(run.data?.ai_tool?.[0]?.[0]?.json?.message && {
        output: run.data.ai_tool[0][0].json.message
      }),
      ...(run.metadata?.subExecution?.executionId && {
        subExecutionId: run.metadata.subExecution.executionId
      }),
    }))
  );

return {
  json: {
    date: new Date().toISOString(),
    source: triggerData.source,
    agent: triggerData.Agent,
    user_id: triggerData.user_id,
    phone_no: triggerData.phone_no,
    ...(hasTokens && {
      input_tokens: tokenTotals.input,
      output_tokens: tokenTotals.output,
      total_tokens: tokenTotals.total,
    }),
    ...(toolsCalled.length > 0 && {
      tools_count: toolsCalled.length,
      tool_names: toolsCalled.map(t => t.tool).join(', '),
    }),
  }
};

